#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use DBI;

my $cgi = CGI->new();
my $username = $cgi->param('username');
my $password = $cgi->param('password');

if (!defined($username) || !defined($password)) {
    print "Content-type: text/html\n\n";
    print "<html><body>Username and password are required.</body></html>";
    exit;
}

my $dsn = 'DBI:mysql:database=mydb;host=localhost';
my $user = 'myuser';
my $pass = 'mypassword';

my $dbh = DBI->connect($dsn, $user, $pass) or die "Cannot connect to database: $DBI::errstr";

my $query = "SELECT * FROM users WHERE username='$username' AND password='$password'";
my $sth = $dbh->prepare($query);
$sth->execute();

if ($sth->rows > 0) {
    print "Content-type: text/html\n\n";
    print "<html><body>Login successful.</body></html>";
} else {
    print "Content-type: text/html\n\n";
    print "<html><body>Invalid username or password.</body></html>";
}

$dbh->disconnect();